export enum AppStage {
  DIAGNOSIS = 0,
  ASSETS = 1,
  STRUCTURE = 2,
  MARKET_RESEARCH = 3,
  REVIEW = 4,
}

export interface CanvasSection {
  title: string;
  points: string[]; // Bullet points for the dashboard card
  detail: string;   // Extended explanation for the modal
}

export interface BusinessCanvasData {
  keyPartners: CanvasSection;
  keyActivities: CanvasSection;
  valuePropositions: CanvasSection;
  customerRelationships: CanvasSection;
  customerSegments: CanvasSection;
  keyResources: CanvasSection;
  channels: CanvasSection;
  costStructure: CanvasSection;
  revenueStreams: CanvasSection;
}

export interface BusinessData {
  hasProduct: boolean;
  hasLogo: boolean;
  hasMarketTarget: boolean;

  businessName: string;
  industry: string;

  logoUrl?: string;
  mockupUrl?: string;
  productIdeas: string[];
  selectedProductIdea?: string;

  mission: string;
  vision: string;
  targetAudience: string;
  shortTermGoals: string;

  // Market Research
  location: string;
  marketAnalysis?: string; // Detailed text
  marketSummary?: string[]; // Key bullet points
  marketSources?: { title: string; uri: string }[];

  // Now stores the Canvas JSON object
  actionPlan?: BusinessCanvasData | null; 
}

export interface GenerationState {
  isGeneratingLogo: boolean;
  isGeneratingMockup: boolean;
  isGeneratingIdeas: boolean;
  isRefiningMission: boolean;
  isRefiningVision: boolean;
  isPerformingResearch: boolean;
  isGeneratingPlan: boolean;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const FLASH_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export const generateBusinessIdeas = async (interests: string, sector: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: FLASH_MODEL,
      contents: `Actúa como un consultor de negocios venezolano experto. Genera 3 ideas de negocio innovadoras y rentables para alguien interesado en: "${interests}" dentro del sector "${sector}". 
      Las ideas deben ser aterrizadas a la realidad de Venezuela pero modernas.
      Devuelve solo un array JSON de strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error generating ideas:", error);
    return ["Error al generar ideas"];
  }
};

export const generateLogo = async (brandName: string, style: string, colors: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: `Diseña un logotipo minimalista, moderno y vectorial para una empresa llamada "${brandName}". Estilo: ${style}. Paleta de colores: ${colors}. El fondo debe ser blanco puro.`,
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return part ? `data:image/png;base64,${part.inlineData.data}` : null;
  } catch (error) {
    return null;
  }
};

export const generateMockup = async (logoBase64: string, objectDescription: string): Promise<string | null> => {
  try {
    const base64Data = logoBase64.includes(',') ? logoBase64.split(',')[1] : logoBase64;
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: 'image/png' } },
          { text: `Este es el logo de una marca. Crea un mockup publicitario fotorrealista aplicando este logo sobre un/a ${objectDescription}. El resultado debe ser profesional, estético y listo para un catálogo de marketing.` }
        ]
      }
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return part ? `data:image/png;base64,${part.inlineData.data}` : null;
  } catch (error) {
    console.error("Error generating mockup:", error);
    return null;
  }
};

export const performMarketResearch = async (location: string, businessType: string) => {
  try {
    const response = await ai.models.generateContent({
      model: FLASH_MODEL,
      contents: `Investiga el mercado para un negocio de "${businessType}" en la ubicación específica: "${location}". 

      Estructura la respuesta en JSON con dos partes:
      1. "summary": Un array de 4 puntos clave muy breves y directos sobre la viabilidad y oportunidades (máximo 15 palabras por punto).
      2. "analysis": Un texto detallado en formato Markdown sobre saturación, perfil del consumidor y competencia.

      Sé realista, objetivo y adapta el tono a un asesor de negocios profesional.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.ARRAY, items: { type: Type.STRING } },
            analysis: { type: Type.STRING }
          }
        }
      }
    });

    const parsed = JSON.parse(response.text || "{}");

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Fuente Externa',
      uri: chunk.web?.uri || '#'
    })) || [];

    return {
      summary: parsed.summary || [],
      analysis: parsed.analysis || "No se pudo completar el análisis detallado.",
      sources
    };
  } catch (error) {
    return { summary: [], analysis: "Error al realizar la investigación de mercado.", sources: [] };
  }
};

export const refineText = async (currentText: string, type: 'mission' | 'vision' | 'goals', context: string): Promise<string> => {

  let prompt = "";

  if (type === 'goals') {
    prompt = `Actúa como un gerente de negocios pragmático y orientado a resultados. Refina estos objetivos de negocio para una empresa de ${context}: "${currentText}".

    Reglas OBLIGATORIAS:
    1. El resultado debe ser PRAGMÁTICO, CONCRETO y MEDIBLE (estilo SMART).
    2. ELIMINA todo lenguaje poético, sentimental, soñador o "vende humos". 
    3. Sé directo al grano. Usa verbos de acción.
    4. Respeta la intención original del usuario, no inventes objetivos nuevos que no tengan relación.
    5. Máximo 3 oraciones.`;
  } else {
    // Mission or Vision
    prompt = `Actúa como un redactor publicitario experto. Mejora la redacción de esta ${type} para un negocio de ${context}: "${currentText}".

    Reglas OBLIGATORIAS:
    1. BASATE 100% en lo que escribió el usuario. Simplemente pule la redacción y ortografía.
    2. NO agregues información inventada ni cambies el giro del negocio.
    3. Hazlo sonar profesional pero cercano y moderno.
    4. Mantenlo corto (máximo 2 frases).`;
  }

  const response = await ai.models.generateContent({
    model: FLASH_MODEL,
    contents: prompt,
  });
  return response.text || currentText;
};

// Updated to generate Business Canvas Model JSON
export const generateCanvasData = async (data: any): Promise<any> => {
  const { logoUrl, mockupUrl, actionPlan, ...cleanData } = data;

  const prompt = `
    Actúa como un consultor de negocios experto.
    Genera un MODELO CANVAS DE NEGOCIO (Business Model Canvas) completo y estructurado en formato JSON para: "${cleanData.businessName}" (${cleanData.industry}).
    Ubicación: ${cleanData.location}.

    Contexto:
    Misión: ${cleanData.mission}
    Target: ${cleanData.targetAudience}

    Debes llenar las 9 secciones del canvas. 
    Para cada sección, proporciona:
    - "points": Un array de 3-5 puntos clave muy breves (max 6 palabras cada uno).
    - "detail": Un párrafo explicativo detallado y estratégico (aprox 50-80 palabras) que se mostrará al ampliar. Usa lenguaje sencillo y directo en español.

    El JSON debe tener EXACTAMENTE esta estructura de claves:
    {
      "keyPartners": { "title": "Socios Clave", "points": [], "detail": "" },
      "keyActivities": { "title": "Actividades Clave", "points": [], "detail": "" },
      "keyResources": { "title": "Recursos Clave", "points": [], "detail": "" },
      "valuePropositions": { "title": "Propuestas de Valor", "points": [], "detail": "" },
      "customerRelationships": { "title": "Relaciones con Clientes", "points": [], "detail": "" },
      "channels": { "title": "Canales", "points": [], "detail": "" },
      "customerSegments": { "title": "Segmentos de Clientes", "points": [], "detail": "" },
      "costStructure": { "title": "Estructura de Costes", "points": [], "detail": "" },
      "revenueStreams": { "title": "Fuentes de Ingresos", "points": [], "detail": "" }
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: FLASH_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Error generating canvas data:", error);
    return null;
  }
};

