import { GoogleGenAI, Type, Schema } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const FLASH_MODEL = 'gemini-3-flash-preview';
const IMAGE_MODEL = 'gemini-2.5-flash-image';

export const generateBusinessIdeas = async (interests: string, sector: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: FLASH_MODEL,
      contents: `Actúa como un consultor de negocios experto en el mercado latinoamericano. Genera 3 ideas de negocio innovadoras y rentables para alguien interesado en: "${interests}" dentro del sector "${sector}". 
      Las ideas deben ser viables en el contexto de Latinoamérica pero modernas.
      Devuelve solo un array JSON de strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error generating ideas:", error);
    return ["Error al generar ideas"];
  }
};

export const generateLogo = async (brandName: string, style: string, colors: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: `Diseña un logotipo minimalista, moderno y vectorial para una empresa llamada "${brandName}". Estilo: ${style}. Paleta de colores: ${colors}. El fondo debe ser blanco puro.`,
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return part ? `data:image/png;base64,${part.inlineData.data}` : null;
  } catch (error) {
    return null;
  }
};

export const generateMockup = async (logoBase64: string, objectDescription: string): Promise<string | null> => {
  try {
    const base64Data = logoBase64.includes(',') ? logoBase64.split(',')[1] : logoBase64;
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType: 'image/png' } },
          { text: `Este es el logo de una marca. Crea un mockup publicitario fotorrealista aplicando este logo sobre un/a ${objectDescription}. El resultado debe ser profesional, estético y listo para un catálogo de marketing.` }
        ]
      }
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return part ? `data:image/png;base64,${part.inlineData.data}` : null;
  } catch (error) {
    console.error("Error generating mockup:", error);
    return null;
  }
};

export const performMarketResearch = async (location: string, businessType: string) => {
  try {
    const response = await ai.models.generateContent({
      model: FLASH_MODEL,
      contents: `Investiga el mercado para un negocio de "${businessType}" en la ubicación específica: "${location}". 

      Estructura la respuesta en JSON con dos partes:
      1. "summary": Un array de 4 puntos clave muy breves y directos sobre la viabilidad y oportunidades (máximo 15 palabras por punto).
      2. "analysis": Un texto detallado en formato Markdown sobre saturación, perfil del consumidor y competencia.

      Sé realista, objetivo y adapta el tono a un asesor de negocios profesional enfocado en Latinoamérica.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.ARRAY, items: { type: Type.STRING } },
            analysis: { type: Type.STRING }
          }
        }
      }
    });

    const parsed = JSON.parse(response.text || "{}");

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Fuente Externa',
      uri: chunk.web?.uri || '#'
    })) || [];

    return {
      summary: parsed.summary || [],
      analysis: parsed.analysis || "No se pudo completar el análisis detallado.",
      sources
    };
  } catch (error) {
    return { summary: [], analysis: "Error al realizar la investigación de mercado.", sources: [] };
  }
};

export const refineText = async (currentText: string, type: 'mission' | 'vision' | 'goals', context: string): Promise<string> => {

  let prompt = "";

  if (type === 'goals') {
    prompt = `Actúa como un gerente de negocios pragmático y orientado a resultados. Refina estos objetivos de negocio para una empresa de ${context}: "${currentText}".

    Reglas OBLIGATORIAS:
    1. El resultado debe ser PRAGMÁTICO, CONCRETO y MEDIBLE (estilo SMART).
    2. ELIMINA todo lenguaje poético, sentimental, soñador o poco realista. 
    3. Sé directo al grano. Usa verbos de acción.
    4. Respeta la intención original del usuario, no inventes objetivos nuevos que no tengan relación.
    5. Máximo 3 oraciones.`;
  } else {
    // Mission or Vision
    prompt = `Actúa como un redactor publicitario experto. Mejora la redacción de esta ${type} para un negocio de ${context}: "${currentText}".

    Reglas OBLIGATORIAS:
    1. BASATE 100% en lo que escribió el usuario. Simplemente pule la redacción y ortografía.
    2. NO agregues información inventada ni cambies el giro del negocio.
    3. Hazlo sonar profesional pero cercano y moderno.
    4. Mantenlo corto (máximo 2 frases).`;
  }

  const response = await ai.models.generateContent({
    model: FLASH_MODEL,
    contents: prompt,
  });
  return response.text || currentText;
};

