        <div className="space-y-3 pt-6">
          <p className="block text-sm font-bold text-gray-900 dark:text-white mb-2">¿Qué tienes listo hasta ahora?</p>

          {[
            { key: 'hasProduct', icon: Box, label: 'Ya sé qué voy a vender', val: data.hasProduct },
            { key: 'hasLogo', icon: PenTool, label: 'Ya tengo mi logo diseñado', val: data.hasLogo },
            { key: 'hasMarketTarget', icon: Target, label: 'Sé quién es mi cliente ideal', val: data.hasMarketTarget }
          ].map((item) => (
             <label key={item.key} className={`flex items-center p-4 border rounded-xl cursor-pointer transition-all ${item.val ? 'border-brand-500 bg-brand-50 dark:bg-brand-900/20' : 'border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-800'}`}>
                <input 
                  type="checkbox" 
                  checked={item.val}
                  onChange={(e) => updateData({ [item.key]: e.target.checked })}
                  className="w-5 h-5 text-brand-600 rounded focus:ring-brand-500"
                />
                <item.icon className={`ml-3 mr-3 ${item.val ? 'text-brand-600' : 'text-gray-400'}`} size={20} />
                <span className={`font-medium ${item.val ? 'text-brand-900 dark:text-brand-100' : 'text-gray-600 dark:text-gray-400'}`}>{item.label}</span>
              </label>
          ))}
        </div>

        <button
          onClick={onNext}
          disabled={!isFormValid}
          className={`w-full py-4 px-6 rounded-xl font-bold text-white transition-all mt-6 shadow-lg ${isFormValid ? 'bg-brand-600 hover:bg-brand-700 shadow-brand-500/30 hover:scale-[1.02]' : 'bg-gray-300 dark:bg-gray-800 dark:text-gray-600 cursor-not-allowed shadow-none'}`}
        >
          Arrancar Estrategia
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BusinessData } from '../types';
import { generateBusinessIdeas, generateLogo, generateMockup } from '../services/geminiService';
import { Lightbulb, Image as ImageIcon, Loader2, Package, Palette, Brush, Upload, Check } from 'lucide-react';

interface AssetGeneratorPhaseProps {
  data: BusinessData;
  updateData: (updates: Partial<BusinessData>) => void;
  onNext: () => void;
  onBack: () => void;
}

export const AssetGeneratorPhase: React.FC<AssetGeneratorPhaseProps> = ({ data, updateData, onNext, onBack }) => {
  const [loading, setLoading] = useState({ ideas: false, logo: false, mockup: false });
  const [interests, setInterests] = useState('');
  const [mockupPrompt, setMockupPrompt] = useState('Caja de delivery moderna');
  const [logoStyle, setLogoStyle] = useState('Minimalista y Moderno');
  const [logoColors, setLogoColors] = useState('Azul Marino y Dorado');

  const handleIdeas = async () => {
    if (!interests) return;
    setLoading(prev => ({ ...prev, ideas: true }));
    try {
      const ideas = await generateBusinessIdeas(interests, data.industry);
      updateData({ productIdeas: ideas });
    } catch (e) { console.error(e); }
    setLoading(prev => ({ ...prev, ideas: false }));
  };

  const handleLogo = async () => {
    setLoading(prev => ({ ...prev, logo: true }));
    try {
      const logo = await generateLogo(data.businessName, logoStyle, logoColors);
      updateData({ logoUrl: logo || undefined });
    } catch (e) { console.error(e); }
    setLoading(prev => ({ ...prev, logo: false }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateData({ logoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMockup = async () => {
    if (!data.logoUrl) return;
    setLoading(prev => ({ ...prev, mockup: true }));
    try {
      const mockup = await generateMockup(data.logoUrl, mockupPrompt);
      updateData({ mockupUrl: mockup || undefined });
    } catch (e) { console.error(e); }
    setLoading(prev => ({ ...prev, mockup: false }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      {/* 1. Ideas - Only show if NO product defined, otherwise show simple confirmation */}
      {!data.hasProduct ? (
        <div className="bg-white dark:bg-gray-900 p-8 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-800 transition-colors">
          <h3 className="text-xl font-black flex items-center gap-3 mb-6 text-gray-900 dark:text-white">
            <div className="bg-yellow-100 dark:bg-yellow-900/30 p-2 rounded-xl text-yellow-600 dark:text-yellow-400"><Lightbulb size={24} /></div>
            1. Lluvia de Ideas
          </h3>
          <div className="flex flex-col md:flex-row gap-4">
            <textarea 
              className="flex-1 p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-2xl focus:ring-2 focus:ring-brand-500 outline-none resize-none h-24 dark:text-white dark:placeholder-gray-500" 
              placeholder="¿Qué tienes en mente? Ej: Me gusta la repostería y quiero vender dulces los fines de semana..." 
              value={interests} 
              onChange={e => setInterests(e.target.value)} 
            />
            <button 
              onClick={handleIdeas} 
              disabled={loading.ideas || !interests} 
              className="bg-brand-600 hover:bg-brand-700 text-white px-8 rounded-2xl font-bold transition-all disabled:opacity-50 h-24 shadow-lg shadow-brand-500/20"
            >
              {loading.ideas ? <Loader2 className="animate-spin mx-auto" /> : 'Dame Ideas'}
            </button>
          </div>

          {data.productIdeas.length > 0 && (
            <div className="mt-6">
              <p className="text-xs font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3">Elige la que más te guste:</p>
              <div className="flex flex-wrap gap-3">
                {data.productIdeas.map(idea => (
                  <button 
                    key={idea} 
                    onClick={() => updateData({ selectedProductIdea: idea })}
                    className={`px-5 py-2.5 rounded-xl border text-sm font-bold transition-all 
                    ${data.selectedProductIdea === idea 
                      ? 'bg-brand-600 text-white border-brand-600 shadow-md scale-105' 
                      : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-300 border-gray-100 dark:border-gray-700 hover:border-brand-200 dark:hover:border-brand-700'}`}
                  >
                    {idea}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      ) : (
        <div className="bg-green-50 dark:bg-green-900/20 border border-green-100 dark:border-green-800 p-6 rounded-3xl flex items-center gap-4">
           <div className="bg-green-100 dark:bg-green-800 p-3 rounded-full text-green-600 dark:text-green-300">
             <Check size={24} />
           </div>
           <div>
             <h3 className="font-bold text-green-900 dark:text-green-100">Idea Definida</h3>
             <p className="text-sm text-green-700 dark:text-green-300">Ya sabes lo que vas a vender. ¡Sigamos!</p>
           </div>
        </div>
      )}

      <div className="grid md:grid-cols-2 gap-8">
        {/* 2. Identidad Visual */}
        <div className="bg-white dark:bg-gray-900 p-8 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-800 transition-colors">
          <h3 className="text-xl font-black flex items-center gap-3 mb-6 text-gray-900 dark:text-white">
            <div className="bg-purple-100 dark:bg-purple-900/30 p-2 rounded-xl text-purple-600 dark:text-purple-400"><ImageIcon size={24} /></div>
            2. Tu Logo
          </h3>

          {data.hasLogo ? (
            <div className="space-y-4">
               <div className="border-2 border-dashed border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800 rounded-2xl p-6 text-center">
                  <input 
                    type="file" 
                    accept="image/*" 
                    onChange={handleFileUpload}
                    className="hidden" 
                    id="logo-upload"
                  />
                  <label htmlFor="logo-upload" className="cursor-pointer block">
                    <Upload className="mx-auto text-brand-500 mb-2" size={32} />
                    <span className="text-sm font-bold text-gray-700 dark:text-gray-300 block">Sube tu Logo</span>
                    <span className="text-xs text-gray-400">PNG o JPG (Max 5MB)</span>
                  </label>
               </div>
            </div>
          ) : (
            <div className="space-y-4">
              <div className="space-y-3">
                <div>
                  <label className="text-[10px] font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest block mb-1">Estilo</label>
                  <select 
                    value={logoStyle}
                    onChange={e => setLogoStyle(e.target.value)}
                    className="w-full p-3 border border-gray-100 dark:border-gray-700 rounded-xl text-sm font-medium bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                  >
                    <option>Minimalista y Moderno</option>
                    <option>Vintage y Clásico</option>
                    <option>Tecnológico y Futurista</option>
                    <option>Orgánico y Natural</option>
                    <option>Lujoso y Elegante</option>
                    <option>Divertido y Vibrante</option>
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest block mb-1">Colores</label>
                  <div className="relative">
                    <Palette className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                    <input 
                      type="text" 
                      value={logoColors} 
                      onChange={e => setLogoColors(e.target.value)}
                      placeholder="Ej: Azul Marino y Dorado"
                      className="w-full p-3 pl-10 border border-gray-100 dark:border-gray-700 rounded-xl text-sm font-medium bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand-500"
                    />
                  </div>
                </div>
              </div>
              <button 
                onClick={handleLogo} 
                disabled={loading.logo} 
                className="w-full bg-purple-600 hover:bg-purple-700 text-white py-4 rounded-2xl font-bold shadow-lg shadow-purple-500/20 transition-all"
              >
                {loading.logo ? <Loader2 className="animate-spin mx-auto" /> : 'Diseñar Logo'}
              </button>
            </div>
          )}

          <div className="mt-4 flex items-center justify-center bg-gray-50 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-gray-200 dark:border-gray-700 aspect-square overflow-hidden relative">
            {data.logoUrl ? (
              <img src={data.logoUrl} className="w-full h-full object-contain p-8 animate-fade-in" alt="Logo" />
            ) : (
              <div className="text-center text-gray-400 dark:text-gray-600 p-8">
                <Brush className="mx-auto mb-2 opacity-20" size={48} />
                <p className="text-xs font-medium uppercase tracking-widest">{data.hasLogo ? 'Sube tu archivo' : 'El logo sale aquí'}</p>
              </div>
            )}
          </div>
        </div>

        {/* 3. Mockups */}
        <div className="bg-white dark:bg-gray-900 p-8 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-800 transition-colors">
          <h3 className="text-xl font-black flex items-center gap-3 mb-6 text-gray-900 dark:text-white">
            <div className="bg-indigo-100 dark:bg-indigo-900/30 p-2 rounded-xl text-indigo-600 dark:text-indigo-400"><Package size={24} /></div>
            3. ¿Cómo se ve?
          </h3>
          <div className="space-y-4">
            <div className="relative">
              <label className="text-[10px] font-black text-gray-400 dark:text-gray-500 uppercase tracking-widest block mb-1">Objeto / Lugar</label>
              <input 
                className="w-full p-3 border border-gray-100 dark:border-gray-700 rounded-xl text-sm font-medium bg-gray-50 dark:bg-gray-800 dark:text-white outline-none focus:ring-2 focus:ring-brand-500" 
                placeholder="Ej: Una camiseta negra, una taza de café..." 
                value={mockupPrompt}
                onChange={e => setMockupPrompt(e.target.value)}
              />
            </div>
            <button 
              onClick={handleMockup} 
              disabled={loading.mockup || !data.logoUrl} 
              className="w-full bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-2xl font-bold shadow-lg shadow-indigo-500/20 transition-all disabled:bg-gray-200 dark:disabled:bg-gray-800 dark:disabled:text-gray-600 disabled:shadow-none"
            >
              {loading.mockup ? <Loader2 className="animate-spin mx-auto" /> : 'Ver en Producto'}
            </button>
            <div className="flex items-center justify-center bg-gray-50 dark:bg-gray-800 rounded-2xl border-2 border-dashed border-gray-200 dark:border-gray-700 aspect-square overflow-hidden relative">
              {data.mockupUrl ? (
                <img src={data.mockupUrl} className="w-full h-full object-cover animate-fade-in" alt="Mockup de Producto" />
              ) : (
                <div className="text-center text-gray-400 dark:text-gray-600 p-8">
                  <Package className="mx-auto mb-2 opacity-20" size={48} />
                  <p className="text-xs font-medium uppercase tracking-widest text-center px-4">
                    {data.hasLogo ? 'Sube tu logo primero' : 'Diseña tu logo primero'}
                  </p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center pt-8 border-t border-gray-200 dark:border-gray-800">
        <button onClick={onBack} className="flex items-center gap-2 text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300 font-bold uppercase text-[10px] tracking-widest transition-colors">
          &larr; Volver
        </button>
        <button 
          onClick={onNext} 
          className="bg-brand-600 hover:bg-brand-700 text-white px-12 py-4 rounded-2xl font-bold shadow-lg shadow-brand-500/30 transition-all"
        >
          Siguiente: Estructura
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BusinessData } from '../types';
import { refineText } from '../services/geminiService';
import { Target, Eye, Rocket, Wand2, Loader2, Users } from 'lucide-react';

interface StructurePhaseProps {
  data: BusinessData;
  updateData: (updates: Partial<BusinessData>) => void;
  onNext: () => void;
  onBack: () => void;
}

export const StructurePhase: React.FC<StructurePhaseProps> = ({ data, updateData, onNext, onBack }) => {
  const [loadingField, setLoadingField] = useState<string | null>(null);

  const handleRefine = async (field: 'mission' | 'vision' | 'goals') => {
    const currentText = field === 'mission' ? data.mission : field === 'vision' ? data.vision : data.shortTermGoals;
    if (!currentText || currentText.length < 5) return;

    setLoadingField(field);
    try {
      const refined = await refineText(currentText, field, data.industry);
      if (field === 'mission') updateData({ mission: refined });
      if (field === 'vision') updateData({ vision: refined });
      if (field === 'goals') updateData({ shortTermGoals: refined });
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingField(null);
    }
  };

  const isFormValid = data.mission.length > 5 && data.targetAudience.length > 5;

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in">
      <div className="text-center mb-4">
        <h2 className="text-3xl font-bold text-gray-900 dark:text-white">Base Estratégica</h2>
        <p className="text-gray-500 dark:text-gray-400">Vamos a definir el ADN de tu negocio. Si necesitas ayuda, la IA te ayuda a pulir lo que escribas.</p>
      </div>

      <div className="grid gap-6">
        {/* Misión */}
        <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 transition-all hover:shadow-md">
          <div className="flex justify-between items-center mb-3">
            <label className="font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <Target size={20} className="text-brand-500" /> Misión (¿Qué haces hoy?)
            </label>
            <button 
              onClick={() => handleRefine('mission')} 
              disabled={loadingField === 'mission' || !data.mission}
              className="text-xs font-bold text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/30 hover:bg-brand-100 dark:hover:bg-brand-900/50 px-3 py-1.5 rounded-lg flex items-center gap-1.5 transition-colors disabled:opacity-50"
            >
              {loadingField === 'mission' ? <Loader2 className="animate-spin" size={14} /> : <Wand2 size={14} />}
              Mejorar Redacción
            </button>
          </div>
          <textarea 
            className="w-full p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl h-28 focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none text-gray-700 dark:text-gray-200 transition-all" 
            placeholder="Escribe aquí a qué se dedica tu negocio y qué le ofreces a tus clientes. Sé directo. Ej: Ofrecemos hamburguesas con sabor casero a precios accesibles..." 
            value={data.mission} 
            onChange={e => updateData({ mission: e.target.value })} 
          />
        </div>

        {/* Visión */}
        <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 transition-all hover:shadow-md">
          <div className="flex justify-between items-center mb-3">
            <label className="font-bold text-gray-800 dark:text-white flex items-center gap-2">
              <Eye size={20} className="text-brand-500" /> Visión (¿A dónde vas?)
            </label>
            <button 
              onClick={() => handleRefine('vision')} 
              disabled={loadingField === 'vision' || !data.vision}
              className="text-xs font-bold text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/30 hover:bg-brand-100 dark:hover:bg-brand-900/50 px-3 py-1.5 rounded-lg flex items-center gap-1.5 transition-colors disabled:opacity-50"
            >
              {loadingField === 'vision' ? <Loader2 className="animate-spin" size={14} /> : <Wand2 size={14} />}
              Mejorar Redacción
            </button>
          </div>
          <textarea 
            className="w-full p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl h-28 focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none text-gray-700 dark:text-gray-200 transition-all" 
            placeholder="Sueña en grande: ¿cómo te imaginas tu negocio en unos años? Ej: Quiero ser la referencia de repuestos en toda la región..." 
            value={data.vision} 
            onChange={e => updateData({ vision: e.target.value })} 
          />
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          {/* Público Objetivo */}
          <div className={`bg-white dark:bg-gray-900 p-6 rounded-2xl shadow-sm border ${data.hasMarketTarget ? 'border-brand-200 dark:border-brand-900' : 'border-gray-100 dark:border-gray-800'} transition-all hover:shadow-md`}>
            <label className="font-bold text-gray-800 dark:text-white flex items-center gap-2 mb-3">
              <Users size={20} className="text-brand-500" /> 
              {data.hasMarketTarget ? 'Tus Clientes (Definido)' : '¿A quién le vendes?'}
            </label>
            <div className="relative">
              {data.hasMarketTarget && (
                <div className="absolute top-2 right-2 text-[10px] bg-brand-100 dark:bg-brand-900 text-brand-700 dark:text-brand-300 px-2 py-1 rounded font-bold">
                  MANUAL
                </div>
              )}
              <textarea 
                className="w-full p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl h-36 focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none text-gray-700 dark:text-gray-200 transition-all text-sm" 
                placeholder={data.hasMarketTarget ? "Pega aquí la descripción detallada de tu mercado..." : "Describe a tu cliente: ¿Son jóvenes, adultos, empresas? ¿De dónde son? ¿Qué les gusta?"}
                value={data.targetAudience} 
                onChange={e => updateData({ targetAudience: e.target.value })} 
              />
            </div>
          </div>

          {/* Objetivos */}
          <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 transition-all hover:shadow-md">
            <div className="flex justify-between items-center mb-3">
              <label className="font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <Rocket size={20} className="text-brand-500" /> Objetivos a Corto Plazo
              </label>
              <button 
                onClick={() => handleRefine('goals')} 
                disabled={loadingField === 'goals' || !data.shortTermGoals}
                className="text-xs font-bold text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/30 hover:bg-brand-100 dark:hover:bg-brand-900/50 px-3 py-1.5 rounded-lg flex items-center gap-1.5 transition-colors disabled:opacity-50"
              >
                {loadingField === 'goals' ? <Loader2 className="animate-spin" size={14} /> : <Wand2 size={14} />}
                Hacerlo Pragmático
              </button>
            </div>
            <textarea 
              className="w-full p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl h-36 focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none text-gray-700 dark:text-gray-200 transition-all text-sm" 
              placeholder="Metas claras y realistas. Ej: Vender 50 unidades al mes, lanzar la web en 2 meses..." 
              value={data.shortTermGoals} 
              onChange={e => updateData({ shortTermGoals: e.target.value })} 
            />
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center pt-8 border-t border-gray-200 dark:border-gray-800">
        <button onClick={onBack} className="text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300 font-medium transition-colors">
          Atrás
        </button>
        <button 
          onClick={onNext} 
          disabled={!isFormValid}
          className="bg-brand-600 hover:bg-brand-700 text-white px-12 py-4 rounded-2xl font-bold shadow-lg shadow-brand-500/30 transition-all disabled:bg-gray-300 dark:disabled:bg-gray-800 disabled:shadow-none"
        >
          Investigar Mercado
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { BusinessData } from '../types';
import { performMarketResearch } from '../services/geminiService';
import { MapPin, Search, Loader2, Globe, ExternalLink, ChevronDown, ChevronUp, Lightbulb } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface MarketResearchPhaseProps {
  data: BusinessData;
  updateData: (updates: Partial<BusinessData>) => void;
  onNext: () => void;
  onBack: () => void;
}

export const MarketResearchPhase: React.FC<MarketResearchPhaseProps> = ({ data, updateData, onNext, onBack }) => {
  const [loading, setLoading] = useState(false);
  const [showDetails, setShowDetails] = useState(false);

