        <div className="max-w-md mx-auto flex gap-2">
          <div className="relative flex-1">
            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              className="w-full pl-10 pr-4 py-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-brand-500 dark:text-white" 
              placeholder="Ej: Bogotá, Chapinero / Ciudad de México, Polanco" 
              value={data.location}
              onChange={e => updateData({ location: e.target.value })}
            />
          </div>
          <button 
            onClick={handleResearch} 
            disabled={loading || !data.location}
            className="bg-brand-600 text-white px-6 rounded-xl flex items-center gap-2 font-bold hover:bg-brand-700 transition-colors shadow-lg shadow-brand-500/20"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Search size={18} />}
            Investigar
          </button>
        </div>
      </div>

      {data.marketAnalysis && (
        <div className="space-y-4 animate-fade-in">

          {/* Key Insights Cards */}
          {data.marketSummary && data.marketSummary.length > 0 && (
             <div className="grid md:grid-cols-2 gap-4">
               {data.marketSummary.map((point, i) => (
                 <div key={i} className="bg-white dark:bg-gray-900 p-5 rounded-xl border-l-4 border-brand-500 shadow-sm border-y border-r border-gray-100 dark:border-gray-800 flex items-start gap-3">
                    <Lightbulb className="text-brand-500 shrink-0 mt-1" size={18} />
                    <p className="text-sm font-medium text-gray-700 dark:text-gray-200">{point}</p>
                 </div>
               ))}
             </div>
          )}

          {/* Detailed Analysis Accordion */}
          <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 overflow-hidden">
            <button 
              onClick={() => setShowDetails(!showDetails)}
              className="w-full flex items-center justify-between p-6 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors"
            >
              <div className="flex items-center gap-3 text-gray-900 dark:text-white">
                <Globe size={20} className="text-brand-600" />
                <h3 className="font-bold text-lg">Análisis Profundo del Mercado</h3>
              </div>
              {showDetails ? <ChevronUp className="text-gray-400" /> : <ChevronDown className="text-gray-400" />}
            </button>

            {showDetails && (
              <div className="px-8 pb-8 animate-slide-up">
                <div className="prose prose-sm max-w-none text-gray-700 dark:text-gray-300 dark:prose-invert border-t border-gray-100 dark:border-gray-800 pt-6">
                  <ReactMarkdown>{data.marketAnalysis}</ReactMarkdown>
                </div>

                {data.marketSources && data.marketSources.length > 0 && (
                  <div className="mt-6 pt-6 border-t border-gray-100 dark:border-gray-800">
                    <p className="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase mb-3">Fuentes Consultadas:</p>
                    <div className="flex flex-wrap gap-2">
                      {data.marketSources.map((source, i) => (
                        <a 
                          key={i} 
                          href={source.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center gap-1 text-[10px] bg-gray-50 dark:bg-gray-800 hover:bg-gray-100 dark:hover:bg-gray-700 border dark:border-gray-700 px-2 py-1 rounded-full text-brand-600 dark:text-brand-400"
                        >
                          {source.title.slice(0, 30)}... <ExternalLink size={10} />
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
            {!showDetails && (
              <div className="px-8 pb-4 text-sm text-gray-400">
                Toca para ver detalles de competencia, saturación y oportunidades...
              </div>
            )}
          </div>
        </div>
      )}

      <div className="flex justify-between pt-4">
        <button onClick={onBack} className="text-gray-400 dark:text-gray-500 hover:text-gray-600">Atrás</button>
        <button 
          onClick={onNext} 
          disabled={!data.marketAnalysis} 
          className="bg-brand-600 hover:bg-brand-700 text-white px-10 py-3 rounded-xl font-bold disabled:opacity-50 transition-colors shadow-lg shadow-brand-500/30"
        >
          Ver Plan Maestro
        </button>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AppStage, BusinessData } from './types';
import { StepWizard } from './components/StepWizard';
import { DiagnosisPhase } from './components/DiagnosisPhase';
import { AssetGeneratorPhase } from './components/AssetGeneratorPhase';
import { StructurePhase } from './components/StructurePhase';
import { MarketResearchPhase } from './components/MarketResearchPhase';
import { PlanReviewPhase } from './components/PlanReviewPhase';
import { Moon, Sun } from 'lucide-react';

const initialData: BusinessData = {
  hasProduct: false,
  hasLogo: false,
  hasMarketTarget: false,
  businessName: '',
  industry: '',
  location: '',
  productIdeas: [],
  mission: '',
  vision: '',
  targetAudience: '',
  shortTermGoals: '',
  actionPlan: null, // Reset plan
};

const Logo = () => (
  <svg width="40" height="40" viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" className="shrink-0">
    {/* Navy Circle / E part */}
    <path d="M50 85C69.33 85 85 69.33 85 50C85 43.5 83.2 37.5 80 32.2" stroke="#163250" strokeWidth="8" strokeLinecap="round" className="dark:stroke-white"/>
    <path d="M20 32.2C16.8 37.5 15 43.5 15 50C15 69.33 30.67 85 50 85" stroke="#163250" strokeWidth="8" strokeLinecap="round" className="dark:stroke-white"/>
    <path d="M80 67.8C83.2 62.5 85 56.5 85 50" stroke="#163250" strokeWidth="8" strokeLinecap="round" className="dark:stroke-white"/>
    <path d="M50 15C43.5 15 37.5 16.8 32.2 20" stroke="#163250" strokeWidth="8" strokeLinecap="round" className="dark:stroke-white"/>

    {/* Inner E shape approximation */}
    <path d="M30 65C30 65 35 75 50 75C65 75 75 65 75 50C75 35 65 25 50 25C35 25 25 35 25 50" stroke="#163250" strokeWidth="8" strokeLinecap="round" className="dark:stroke-white"/>

    {/* Teal Arrow Graph */}
    <path d="M15 75 L35 60 L50 75 L85 40" stroke="#00A79D" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round"/>
    <path d="M75 40 H85 V50" stroke="#00A79D" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round"/>
    <path d="M85 40 H75" stroke="#00A79D" strokeWidth="8" strokeLinecap="round" strokeLinejoin="round"/>
  </svg>
);

const App: React.FC = () => {
  const [stage, setStage] = useState<AppStage>(AppStage.DIAGNOSIS);
  const [data, setData] = useState<BusinessData>(initialData);
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const updateData = (updates: Partial<BusinessData>) => {
    setData((prev) => ({ ...prev, ...updates }));
  };

  const resetApp = () => {
    setData(initialData);
    setStage(AppStage.DIAGNOSIS);
  };

  const renderStage = () => {
    switch (stage) {
      case AppStage.DIAGNOSIS:
        return <DiagnosisPhase data={data} updateData={updateData} onNext={() => setStage(AppStage.ASSETS)} />;
      case AppStage.ASSETS:
        return <AssetGeneratorPhase data={data} updateData={updateData} onNext={() => setStage(AppStage.STRUCTURE)} onBack={() => setStage(AppStage.DIAGNOSIS)} />;
      case AppStage.STRUCTURE:
        return <StructurePhase data={data} updateData={updateData} onNext={() => setStage(AppStage.MARKET_RESEARCH)} onBack={() => setStage(AppStage.ASSETS)} />;
      case AppStage.MARKET_RESEARCH:
        return <MarketResearchPhase data={data} updateData={updateData} onNext={() => setStage(AppStage.REVIEW)} onBack={() => setStage(AppStage.STRUCTURE)} />;
      case AppStage.REVIEW:
        return <PlanReviewPhase data={data} updateData={updateData} onBack={() => setStage(AppStage.MARKET_RESEARCH)} onReset={resetApp} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-950 flex flex-col transition-colors duration-300">
      <header className="bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 px-8 py-4 flex justify-between items-center print:hidden sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <Logo />
          <h1 className="text-2xl font-black text-navy-900 dark:text-white tracking-tight flex items-center">
            emprende<span className="text-navy-900 dark:text-white">IA</span>
          </h1>
        </div>

        <button 
          onClick={() => setDarkMode(!darkMode)}
          className="p-2 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
          title={darkMode ? "Modo Claro" : "Modo Oscuro"}
        >
          {darkMode ? <Sun size={20} /> : <Moon size={20} />}
        </button>
      </header>

      <main className="flex-1 px-4 py-8 max-w-6xl mx-auto w-full">
        {stage !== AppStage.REVIEW && (
           <div className="print:hidden"><StepWizard currentStage={stage} /></div>
        )}
        {renderStage()}
      </main>

      <footer className="py-6 text-center text-gray-400 dark:text-gray-600 text-xs print:hidden">
        Powered by Gemini • Estrategia & Diseño IA
      </footer>
    </div>
  );
};

export default App;

