              <textarea 
                className="w-full p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl h-36 focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none text-gray-700 dark:text-gray-200 transition-all text-sm" 
                placeholder={data.hasMarketTarget ? "Pega aquí la descripción detallada de tu mercado..." : "Describe a tu cliente: ¿Son jóvenes, adultos, empresas? ¿De dónde son? ¿Qué les gusta?"}
                value={data.targetAudience} 
                onChange={e => updateData({ targetAudience: e.target.value })} 
              />
            </div>
          </div>

          {/* Objetivos */}
          <div className="bg-white dark:bg-gray-900 p-6 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 transition-all hover:shadow-md">
            <div className="flex justify-between items-center mb-3">
              <label className="font-bold text-navy-900 dark:text-white flex items-center gap-2">
                <Rocket size={20} className="text-brand-500" /> Objetivos a Corto Plazo
              </label>
              <button 
                onClick={() => handleRefine('goals')} 
                disabled={loadingField === 'goals' || !data.shortTermGoals}
                className="text-xs font-bold text-brand-600 dark:text-brand-400 bg-brand-50 dark:bg-brand-900/30 hover:bg-brand-100 dark:hover:bg-brand-900/50 px-3 py-1.5 rounded-lg flex items-center gap-1.5 transition-colors disabled:opacity-50"
              >
                {loadingField === 'goals' ? <Loader2 className="animate-spin" size={14} /> : <Wand2 size={14} />}
                Hacerlo Pragmático
              </button>
            </div>
            <textarea 
              className="w-full p-4 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl h-36 focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none text-gray-700 dark:text-gray-200 transition-all text-sm" 
              placeholder="Metas claras y realistas. Ej: Vender 50 unidades al mes, lanzar la web en 2 meses..." 
              value={data.shortTermGoals} 
              onChange={e => updateData({ shortTermGoals: e.target.value })} 
            />
          </div>
        </div>
      </div>

      <div className="flex justify-between items-center pt-8 border-t border-gray-200 dark:border-gray-800">
        <button onClick={onBack} className="text-gray-400 dark:text-gray-500 hover:text-gray-600 dark:hover:text-gray-300 font-medium transition-colors">
          Atrás
        </button>
        <button 
          onClick={onNext} 
          disabled={!isFormValid}
          className="bg-brand-600 hover:bg-brand-700 text-white px-12 py-4 rounded-2xl font-bold shadow-lg shadow-brand-500/30 transition-all disabled:bg-gray-300 dark:disabled:bg-gray-800 disabled:shadow-none"
        >
          Investigar Mercado
        </button>
      </div>
