import React, { useState } from 'react';
import { BusinessData } from '../types';
import { performMarketResearch } from '../services/geminiService';
import { MapPin, Search, Loader2, Globe, ExternalLink, ChevronDown, ChevronUp, Lightbulb } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

interface MarketResearchPhaseProps {
  data: BusinessData;
  updateData: (updates: Partial<BusinessData>) => void;
  onNext: () => void;
  onBack: () => void;
}

export const MarketResearchPhase: React.FC<MarketResearchPhaseProps> = ({ data, updateData, onNext, onBack }) => {
  const [loading, setLoading] = useState(false);
  const [showDetails, setShowDetails] = useState(false);

  const handleResearch = async () => {
    if (!data.location) return;
    setLoading(true);
    const result = await performMarketResearch(data.location, data.industry);
    updateData({ 
      marketAnalysis: result.analysis, 
      marketSummary: result.summary,
      marketSources: result.sources 
    });
    setLoading(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-gray-900 p-8 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 text-center transition-colors">
        <h2 className="text-2xl font-bold mb-2 text-navy-900 dark:text-white">Estudio de Zona</h2>
        <p className="text-gray-500 dark:text-gray-400 mb-6">Dime dónde quieres establecer el negocio y Gemini te dice cómo es la zona.</p>

        <div className="max-w-md mx-auto flex gap-2">
          <div className="relative flex-1">
            <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input 
              className="w-full pl-10 pr-4 py-3 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-brand-500 dark:text-white" 
              placeholder="Ej: Bogotá, Chapinero / Ciudad de México, Polanco" 
              value={data.location}
              onChange={e => updateData({ location: e.target.value })}
            />
          </div>
          <button 
            onClick={handleResearch} 
            disabled={loading || !data.location}
            className="bg-brand-600 text-white px-6 rounded-xl flex items-center gap-2 font-bold hover:bg-brand-700 transition-colors shadow-lg shadow-brand-500/20"
          >
            {loading ? <Loader2 className="animate-spin" /> : <Search size={18} />}
            Investigar
          </button>
        </div>
      </div>

      {data.marketAnalysis && (
        <div className="space-y-4 animate-fade-in">

          {/* Key Insights Cards */}
          {data.marketSummary && data.marketSummary.length > 0 && (
             <div className="grid md:grid-cols-2 gap-4">
               {data.marketSummary.map((point, i) => (
                 <div key={i} className="bg-white dark:bg-gray-900 p-5 rounded-xl border-l-4 border-brand-500 shadow-sm border-y border-r border-gray-100 dark:border-gray-800 flex items-start gap-3">
                    <Lightbulb className="text-brand-500 shrink-0 mt-1" size={18} />
                    <p className="text-sm font-medium text-gray-700 dark:text-gray-200">{point}</p>
                 </div>
               ))}
             </div>
          )}

          {/* Detailed Analysis Accordion */}
          <div className="bg-white dark:bg-gray-900 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 overflow-hidden">
            <button 
              onClick={() => setShowDetails(!showDetails)}
              className="w-full flex items-center justify-between p-6 hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors"
            >
              <div className="flex items-center gap-3 text-navy-900 dark:text-white">
                <Globe size={20} className="text-brand-600" />
                <h3 className="font-bold text-lg">Análisis Profundo del Mercado</h3>
              </div>
              {showDetails ? <ChevronUp className="text-gray-400" /> : <ChevronDown className="text-gray-400" />}
            </button>

            {showDetails && (
              <div className="px-8 pb-8 animate-slide-up">
                <div className="prose prose-sm max-w-none text-gray-700 dark:text-gray-300 dark:prose-invert border-t border-gray-100 dark:border-gray-800 pt-6">
                  <ReactMarkdown>{data.marketAnalysis}</ReactMarkdown>
                </div>

                {data.marketSources && data.marketSources.length > 0 && (
                  <div className="mt-6 pt-6 border-t border-gray-100 dark:border-gray-800">
                    <p className="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase mb-3">Fuentes Consultadas:</p>
                    <div className="flex flex-wrap gap-2">
                      {data.marketSources.map((source, i) => (
                        <a 
                          key={i} 
                          href={source.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="flex items-center gap-1 text-[10px] bg-gray-50 dark:bg-gray-800 hover:bg-gray-100 dark:hover:bg-gray-700 border dark:border-gray-700 px-2 py-1 rounded-full text-brand-600 dark:text-brand-400"
                        >
                          {source.title.slice(0, 30)}... <ExternalLink size={10} />
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}
            {!showDetails && (
              <div className="px-8 pb-4 text-sm text-gray-400">
                Toca para ver detalles de competencia, saturación y oportunidades...
              </div>
            )}
          </div>
        </div>
      )}

      <div className="flex justify-between pt-4">
        <button onClick={onBack} className="text-gray-400 dark:text-gray-500 hover:text-gray-600">Atrás</button>
        <button 
          onClick={onNext} 
          disabled={!data.marketAnalysis} 
          className="bg-brand-600 hover:bg-brand-700 text-white px-10 py-3 rounded-xl font-bold disabled:opacity-50 transition-colors shadow-lg shadow-brand-500/30"
        >
          Ver Plan Maestro
        </button>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { BusinessData, BusinessCanvasData, CanvasSection } from '../types';
import { generateCanvasData } from '../services/geminiService';
import { 
  Loader2, RefreshCcw, X, 
  Handshake, Settings, Package, Heart, Users, 
  Box, Truck, BarChart3, Wallet, ArrowUpRight
} from 'lucide-react';

interface PlanReviewPhaseProps {
  data: BusinessData;
  updateData: (updates: Partial<BusinessData>) => void;
  onBack: () => void;
  onReset: () => void;
}

export const PlanReviewPhase = ({ data, updateData, onBack, onReset }: PlanReviewPhaseProps) => {
  const [loading, setLoading] = useState(false);
  const [selectedSection, setSelectedSection] = useState<{key: string, data: CanvasSection, color: string} | null>(null);

  useEffect(() => {
    if (!data.actionPlan) {
      const create = async () => {
        setLoading(true);
        try {
          const canvasJson = await generateCanvasData(data);
          updateData({ actionPlan: canvasJson });
        } catch (e) {
          console.error(e);
        } finally {
          setLoading(false);
        }
      };
      create();
    }
  }, []);

  const plan = data.actionPlan as BusinessCanvasData | null;

  if (loading || !plan) return (
